// gc2211 satstar DEBLEND debug -- dev frame jw02211023001_02201_00001_nrca1 (F200W, obs023)
// Layers (blink): crf data | ZEROFRAME (frame zero) | satstar MODEL | satstar RESIDUAL
// Catalogs: satstar fit catalog | NEW deblended centres | OLD one-per-blob centroids
// Zoom to a known merged double to compare old(orange) vs new(green) seeds:
//   L168 double  px=(1040,1565)  sky=(266.413835,-28.957891)
//   L15  double  px=(1020, 177)  sky=(266.400005,-28.957988)
//   L31  single  px=( 522, 421)  sky=(266.402416,-28.962323)
const P = "jwst/gc2211/F200W/pipeline/";

// --- images (data / frame-zero / model / residual) ---
await app.appendFile(P + "jw02211023001_02201_00001_nrca1_destreak_jw02211-o023_20260515t014922_image3_00001_crf.fits");
await app.appendFile(P + "jw02211023001_02201_00001_nrca1_zeroframe.fits");
await app.appendFile(P + "jw02211023001_02201_00001_nrca1_destreak_o023_crf_iter3_satstar_model.fits");
await app.appendFile(P + "jw02211023001_02201_00001_nrca1_destreak_o023_crf_iter3_satstar_residual.fits");

// --- catalogs (4th arg = CatalogFileType.VOTable=1 to pass the frontend guard; backend auto-detects FITS) ---
// existing satstar fit catalog (skycoord_fit)
const catSat = await app.appendCatalog(P, "jw02211023001_02201_00001_nrca1_destreak_o023_crf_iter3_satstar_catalog.fits", 500, 1);
let cw = app.catalogStore.getCatalogWidgetStore(catSat);
if (cw) { cw.setxAxis("skycoord_fit.ra"); cw.setyAxis("skycoord_fit.dec"); }

// NEW deblended centres (green): one row per star, n_stars_in_blob>=2 are the deblended doubles
const catNew = await app.appendCatalog(P, "jw02211023001_02201_00001_nrca1_deblend_catalog.fits", 500, 1);
cw = app.catalogStore.getCatalogWidgetStore(catNew);
if (cw) { cw.setxAxis("ra"); cw.setyAxis("dec"); }

// OLD one-centroid-per-blob seeds (orange): compare against NEW to see the merged-core fix
const catOld = await app.appendCatalog(P, "jw02211023001_02201_00001_nrca1_old_satcentroid.fits", 500, 1);
cw = app.catalogStore.getCatalogWidgetStore(catOld);
if (cw) { cw.setxAxis("ra"); cw.setyAxis("dec"); }

for (const frame of app.frames) {
    frame.renderConfig.setScaling(2);          // sqrt
    frame.renderConfig.setCustomScale(-1, 200);
}
